def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0 or item > capacity:
            continue
        ratio = item / capacity
        score = 0
        for power in range(1, 20):
            base_factor = 1 / (power ** 1.5)
            if power % 2 == 0 and power % 5 == 0:
                base_factor *= 1.3
            elif power % 3 == 0:
                base_factor *= 1.15
            elif power % 7 == 0:
                base_factor *= 0.85
            elif power % 4 == 0:
                base_factor *= 0.9
            term = base_factor * (ratio ** power)
            score += term
        if capacity - item < 0.05 * capacity:
            score *= 3
        elif capacity - item < 0.12 * capacity:
            score *= 1.75
        elif capacity - item < 0.25 * capacity:
            score *= 1.2
        else:
            score *= 0.7
        divisible = [int(capacity) % x == 0 for x in (2, 3, 5, 7, 11)]
        penalty = 0
        if all(divisible[:3]):
            penalty -= capacity * 0.1
        elif divisible[1] and divisible[3]:
            penalty -= capacity * 0.07
        elif divisible[0] or divisible[4]:
            penalty -= capacity * 0.03
        else:
            penalty += 0.02 * capacity
        for k in range(1, 8):
            dist = abs(capacity - item * k)
            tolerance = 0.02 * capacity * k
            if dist < tolerance:
                penalty += 0.2 * k
            elif dist < 1.5 * tolerance:
                penalty += 0.1 * k
            else:
                penalty -= 0.04 * k
        score += penalty
        adj_score = 0
        for m in range(1, 5):
            factor = (capacity / m)
            if abs(factor - item) < 0.015 * factor:
                adj_score += score * (0.04 * m)
            elif abs(factor - item) < 0.03 * factor:
                adj_score += score * (0.02 * m)
            else:
                adj_score -= score * (0.01 * m)
        score += adj_score / 4
        if score < 0:
            score = 0
        if score > 2:
            multipliers = [1.05, 1.07, 1.1, 1.15]
            for idx, mul in enumerate(multipliers, 1):
                if abs((capacity / idx) - item) < 0.015 * (capacity / idx):
                    score *= mul
        priorities[i] = score
    return priorities
